css:
.print-heading {
  text-align: center;
  margin-bottom: 28px;
}

.print-heading h2 {
  margin: 0;
  font-size: 18pt;
}

.print-heading p {
  margin: 6px 0 0;
}

.demotion-duration {
  font-weight: 600;
}

.employee-summary {
  margin-bottom: 20px;
}

.summary-table,
.demotion-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #d7d7d7;
  border-radius: 8px;
  overflow: hidden;
  margin-bottom: 20px;
}

.summary-table th,
.summary-table td,
.demotion-table th,
.demotion-table td {
  padding: 8px;
  border-bottom: 1px solid #d7d7d7;
  border-right: 1px solid #d7d7d7;
  vertical-align: top;
}

.summary-table th:last-child,
.summary-table td:last-child,
.demotion-table th:last-child,
.demotion-table td:last-child {
  border-right: none;
}

.summary-table tbody tr:last-child th,
.summary-table tbody tr:last-child td,
.demotion-table tbody tr:last-child th,
.demotion-table tbody tr:last-child td {
  border-bottom: none;
}

.summary-table tbody tr:nth-child(odd),
.demotion-table tbody tr:nth-child(odd) {
  background-color: #fafafa;
}

.summary-label {
  width: 18%;
  font-weight: 600;
  background-color: #f4f4f4;
}

.demotion-table th {
  background-color: #f4f4f4;
  text-align: left;
  font-weight: 600;
}

.demotion-table tr {
  page-break-inside: avoid;
}

.number-column {
  width: 38px;
  text-align: center;
}

.date-column {
  width: 110px;
  white-space: nowrap;
}

.empty-row {
  text-align: center;
  color: #777;
  font-style: italic;
}

.demotion-notice {
  margin: 18px 0 22px;
  padding: 14px 16px;
  border: 1px solid #d4bd91;
  border-left: 4px solid #b87900;
  background-color: #fffaf0;
  page-break-inside: avoid;
}

.demotion-notice p {
  margin: 0 0 10px;
}

.demotion-notice p:last-child {
  margin-bottom: 0;
}

.details-box {
  margin-bottom: 20px;
  padding: 10px 12px;
  border: 1px solid #d7d7d7;
  background-color: #fafafa;
  white-space: pre-wrap;
}

.section-heading {
  margin-top: 22px;
  margin-bottom: 10px;
  padding-bottom: 5px;
  border-bottom: 1px solid #b87900;
  font-size: 12pt;
  font-weight: 600;
  page-break-after: avoid;
}

.acknowledgement {
  margin-top: 22px;
}

.acknowledgement p {
  margin: 0 0 10px;
}

.signatures {
  margin-top: 28px;
}

.signatures table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.signatures tr {
  page-break-inside: avoid;
}

.signatures td {
  border: none;
  vertical-align: bottom;
}

.signatures .signature-cell {
  width: 68%;
  padding: 38px 30px 16px 0;
}

.signatures .date-cell {
  width: 32%;
  padding: 38px 0 16px 20px;
}

.signatures .signature-line {
  min-height: 22px;
  border-bottom: 1px solid #222;
}

.signatures .signature-label {
  margin-top: 5px;
  font-size: 10.5pt;
  line-height: 1.3;
}

.signatures .qualifier {
  font-size: 9pt;
  font-style: italic;
}

@page {
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
